    "home.whatsappAskMessage": "Hola Youssef, me gustaría preguntar sobre tus programas de entrenamiento.",
    "dashboard.progressPhotoAlt": "Foto de progreso",
    "profile.errors.notSignedIn": "No has iniciado sesión",
